import React, { useState, useContext, useEffect } from 'react';
import { AuthContext } from '../contexts/AuthContext';
import { api } from '../services/api';
import { Role, User } from '../types';
import { StudentIcon, MainAdminIcon, MainBankIcon, MainMartIcon, CheckIcon, ErrorIcon } from '../components/icons';

type AuthMode = 'landing' | 'login' | 'signup' | 'recovery' | 'recovery-reset' | 'student-tenant' | 'student-select' | 'app-login' | 'app-change-password';

const AuthPage: React.FC = () => {
    const { login } = useContext(AuthContext);

    const [mode, setMode] = useState<AuthMode>('landing');
    const [loginTarget, setLoginTarget] = useState<{ role: Role, title: string, userId: string } | null>(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [successMessage, setSuccessMessage] = useState('');

    // Teacher Auth State
    const [teacherLoginId, setTeacherLoginId] = useState('');
    const [password, setPassword] = useState('');
    const [teacherAlias, setTeacherAlias] = useState('');
    const [currencyUnit, setCurrencyUnit] = useState('');
    const [recoveryCode, setRecoveryCode] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [recoveryModalVisible, setRecoveryModalVisible] = useState(false);
    const [recoveryConfirmChecked, setRecoveryConfirmChecked] = useState(false);

    // Student App State
    const [studentTeacherId, setStudentTeacherId] = useState(''); // To identify which teacher's class
    const [grade, setGrade] = useState('');
    const [cls, setCls] = useState('');
    const [num, setNum] = useState('');
    const [appPassword, setAppPassword] = useState('');
    const [newAppPassword, setNewAppPassword] = useState('');
    const [students, setStudents] = useState<User[]>([]);

    const handleTeacherSignup = async () => {
        if (!teacherLoginId || !password || !teacherAlias || !currencyUnit) {
            setError('모든 항목을 입력해주세요.');
            return;
        }
        setLoading(true);
        setError('');
        try {
            const result = await api.signupTeacher(teacherLoginId, password, teacherAlias, currencyUnit);
            setRecoveryCode(result.recoveryCode);
            setRecoveryModalVisible(true);
            setSuccessMessage('회원가입이 완료되었습니다!');
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    const handleTeacherLogin = async () => {
        if (!teacherLoginId || !password) return;
        setLoading(true);
        setError('');
        try {
            const user = await api.loginTeacher(teacherLoginId, password);
            if (user) {
                login(user);
            } else {
                setError('아이디 또는 비밀번호가 일치하지 않습니다.');
            }
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    const handleRecoveryVerify = async () => {
        if (!teacherLoginId || !recoveryCode) {
            setError('아이디와 복구 코드를 입력해주세요.');
            return;
        }
        setLoading(true);
        try {
            const isValid = await api.verifyRecoveryCode(teacherLoginId, recoveryCode);
            if (isValid) {
                setMode('recovery-reset');
            } else {
                setError('복구 코드가 일치하지 않습니다.');
            }
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    const handlePasswordReset = async () => {
        if (!newPassword) return;
        setLoading(true);
        try {
            await api.resetTeacherPassword(teacherLoginId, recoveryCode, newPassword);
            setSuccessMessage('비밀번호가 변경되었습니다. 다시 로그인해주세요.');
            setTimeout(() => {
                setMode('login');
                setSuccessMessage('');
            }, 2000);
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    const handleStudentAccess = async () => {
        if (!studentTeacherId) {
            setError('학급 아이디(선생님 ID)를 입력해주세요.');
            return;
        }
        setLoading(true);
        try {
            const teacherExists = await api.checkTeacherExists(studentTeacherId);
            if (teacherExists) {
                const studentList = await api.getUsersByRole(Role.STUDENT, studentTeacherId);
                setStudents(studentList);
                setMode('student-select');
            } else {
                setError('존재하지 않는 학급 아이디입니다.');
            }
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    const handleStudentLogin = async (userId: string) => {
        setLoading(true);
        try {
            const user = await api.login(userId);
            if (user) login(user);
        } catch (err) {
            setError('로그인 중 오류가 발생했습니다.');
        } finally {
            setLoading(false);
        }
    };

    const reset = () => {
        setMode('landing');
        setError('');
        setSuccessMessage('');
        setTeacherLoginId('');
        setPassword('');
    };

    // --- Render Views ---

    if (recoveryModalVisible) {
        return (
            <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
                <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl animate-fadeIn">
                    <div className="bg-amber-50 p-4 rounded-2xl mb-6 flex flex-col items-center">
                        <ErrorIcon className="w-12 h-12 text-amber-500 mb-2" />
                        <h3 className="text-xl font-bold text-amber-900">복구 코드 안내</h3>
                    </div>
                    <p className="text-gray-600 text-center mb-6 leading-relaxed">
                        비밀번호를 잊어버렸을 때 사용하는 <span className="font-bold text-gray-900">비밀번호 복구 코드</span>입니다. 반드시 따로 기록해두세요!
                    </p>
                    <div className="bg-gray-100 p-4 rounded-xl text-center mb-6 font-mono font-extrabold text-2xl tracking-widest text-indigo-600">
                        {recoveryCode}
                    </div>
                    <label className="flex items-center gap-3 mb-8 cursor-pointer group">
                        <input 
                            type="checkbox" 
                            checked={recoveryConfirmChecked} 
                            onChange={e => setRecoveryConfirmChecked(e.target.checked)}
                            className="w-5 h-5 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500" 
                        />
                        <span className="text-sm text-gray-700 group-hover:text-gray-900">코드를 안전하게 기록했습니다.</span>
                    </label>
                    <button 
                        disabled={!recoveryConfirmChecked}
                        onClick={() => { setRecoveryModalVisible(false); setMode('login'); }}
                        className="w-full p-4 bg-indigo-600 text-white font-bold rounded-2xl shadow-lg hover:bg-indigo-700 disabled:bg-gray-300 transition-all active:scale-95"
                    >
                        확인
                    </button>
                </div>
            </div>
        );
    }

    if (mode === 'signup') {
        return (
            <div className="flex flex-col h-full p-6 bg-gray-50 items-center justify-center">
                <div className="w-full max-w-md bg-white p-8 rounded-3xl shadow-xl">
                    <button onClick={() => setMode('landing')} className="text-gray-400 mb-4 hover:text-gray-600">{'<'} 뒤로</button>
                    <h2 className="text-2xl font-bold mb-6 text-gray-800">선생님 가입</h2>
                    <div className="space-y-4">
                        <input type="text" placeholder="아이디 (로그인 ID)" value={teacherLoginId} onChange={e => setTeacherLoginId(e.target.value)} className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" />
                        <input type="password" placeholder="비밀번호" value={password} onChange={e => setPassword(e.target.value)} className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" />
                        <input type="text" placeholder="선생님 별칭 (예: 권쌤, 민수쌤)" value={teacherAlias} onChange={e => setTeacherAlias(e.target.value)} className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" />
                        <input type="text" placeholder="화폐 단위 (예: 권, 원, 달러)" value={currencyUnit} onChange={e => setCurrencyUnit(e.target.value)} className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" />
                        {error && <p className="text-red-500 text-sm text-center">{error}</p>}
                        <button onClick={handleTeacherSignup} disabled={loading} className="w-full p-4 bg-indigo-600 text-white font-bold rounded-2xl shadow-lg hover:bg-indigo-700 transition-all active:scale-95">
                            {loading ? '가입 중...' : '회원가입 완료'}
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    if (mode === 'login') {
        return (
            <div className="flex flex-col h-full p-6 bg-gray-50 items-center justify-center">
                <div className="w-full max-w-md bg-white p-8 rounded-3xl shadow-xl">
                    <button onClick={() => setMode('landing')} className="text-gray-400 mb-4 hover:text-gray-600">{'<'} 뒤로</button>
                    <h2 className="text-2xl font-bold mb-6 text-gray-800 text-center">선생님 로그인</h2>
                    <div className="space-y-4">
                        <input type="text" placeholder="아이디" value={teacherLoginId} onChange={e => setTeacherLoginId(e.target.value)} className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" />
                        <input type="password" placeholder="비밀번호" value={password} onChange={e => setPassword(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleTeacherLogin()} className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" />
                        {error && <p className="text-red-500 text-sm text-center">{error}</p>}
                        <button onClick={handleTeacherLogin} disabled={loading} className="w-full p-4 bg-indigo-600 text-white font-bold rounded-2xl shadow-lg hover:bg-indigo-700 transition-all active:scale-95">
                            {loading ? '로그인 중...' : '로그인'}
                        </button>
                        <button onClick={() => setMode('recovery')} className="w-full text-sm text-gray-400 hover:text-indigo-600 hover:underline">비밀번호 찾기</button>
                    </div>
                </div>
            </div>
        );
    }

    if (mode === 'recovery') {
        return (
            <div className="flex flex-col h-full p-6 bg-gray-50 items-center justify-center">
                <div className="w-full max-w-md bg-white p-8 rounded-3xl shadow-xl">
                    <button onClick={() => setMode('login')} className="text-gray-400 mb-4 hover:text-gray-600">{'<'} 뒤로</button>
                    <h2 className="text-2xl font-bold mb-2 text-gray-800">비밀번호 찾기</h2>
                    <p className="text-sm text-gray-500 mb-6">가입 시 받은 복구 코드를 입력하세요.</p>
                    <div className="space-y-4">
                        <input type="text" placeholder="아이디" value={teacherLoginId} onChange={e => setTeacherLoginId(e.target.value)} className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" />
                        <input type="text" placeholder="복구 코드" value={recoveryCode} onChange={e => setRecoveryCode(e.target.value)} className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" />
                        {error && <p className="text-red-500 text-sm text-center">{error}</p>}
                        <button onClick={handleRecoveryVerify} disabled={loading} className="w-full p-4 bg-amber-500 text-white font-bold rounded-2xl shadow-lg hover:bg-amber-600 transition-all active:scale-95">
                            코드 확인
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    if (mode === 'recovery-reset') {
        return (
            <div className="flex flex-col h-full p-6 bg-gray-50 items-center justify-center">
                <div className="w-full max-w-md bg-white p-8 rounded-3xl shadow-xl">
                    <h2 className="text-2xl font-bold mb-2 text-gray-800">새 비밀번호 설정</h2>
                    <div className="space-y-4 mt-6">
                        <input type="password" placeholder="새 비밀번호" value={newPassword} onChange={e => setNewPassword(e.target.value)} className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" />
