                    <h2 className="text-2xl font-bold mb-2 text-gray-800">학급 입장</h2>
                    <p className="text-sm text-gray-500 mb-6">선생님의 아이디를 입력해주세요.</p>
                    <div className="space-y-4">
                        <input type="text" placeholder="학급 아이디" value={studentTeacherId} onChange={e => setStudentTeacherId(e.target.value)} className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" />
