                    >
                        학생 학급 입장
                    </button>
                    <div className="flex items-center gap-4 py-4">
                        <div className="flex-grow h-px bg-gray-100"></div>
                        <span className="text-xs text-gray-300 font-bold uppercase tracking-widest">or</span>
                        <div className="flex-grow h-px bg-gray-100"></div>
                    </div>
                    <button 
                        onClick={() => setMode('signup')}
