            <ConfirmModal isOpen={confirmAction?.type === 'pay_one'} title="주급 지급" message="이 직업을 담당하는 모든 학생들에게 주급을 지급하시겠습니까?" onConfirm={handlePayOneSalary} onCancel={() => setConfirmAction(null)} />
