                        </label>
                    ))}
                </div>
                <button onClick={handleCreate} disabled={loading} className="w-full py-3 bg-[#2B548F] text-white font-bold rounded-lg">
                    {loading ? '고지 중...' : '고지하기'}
                </button>
                <button onClick={onClose} className="w-full py-2 text-gray-500 mt-2">닫기</button>
            </div>
        </div>
    );
};

