};

const bankerWithdraw = async (userId: string, amount: number): Promise<string> => {
    const { data, error } = await supabase.rpc('banker_transaction', {
        p_student_user_id: userId,
        p_amount: amount,
        p_type: 'Withdrawal'
    });
    handleSupabaseError(error, 'bankerWithdraw');
