                        className="bg-[#0066FF] hover:bg-[#0055DD]"
                    >
                        시작하기
                    </PrimaryButton>
                    <p className="mt-6 text-[10px] text-gray-300">분실 시 문의: sinjoppo@naver.com</p>
                </div>
            </div>
        );
    }

    if (mode === 'signup') {
        return (
