                        <div className="text-center pt-8 border-t border-gray-50 mt-4">
                            <p className="text-xs text-gray-400 mb-1">복구 코드를 분실하셨나요?</p>
                            <p className="text-xs font-black text-gray-900">문의: sinjoppo@naver.com</p>
                        </div>
                    </div>
                </div>
            </div>
        );
