    if (mode === 'recovery-reset') {
        return (
            <div className="flex flex-col h-full bg-[#F9FAFB] items-center justify-center p-6">
                <div className="w-full max-w-[400px] bg-white p-10 rounded-[32px] shadow-[0_20px_50px_rgba(0,0,0,0.04)] border border-gray-100/50">
