            const data = await api.getFunds(currentUser?.userId || '');
            setFunds(data);
        } catch (e) { console.error(e); }
        finally { setLoading(false); }
    }, [currentUser?.userId]);

    useEffect(() => { fetchFunds(); }, [fetchFunds]);

    const handleSettle = async (fundId: string, status: FundStatus) => {
