                            <span className={`text-xs px-2 py-1 rounded font-bold ${f.status === FundStatus.RECRUITING ? 'bg-blue-100 text-blue-700' : f.status === FundStatus.ONGOING ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-700'}`}>
                                {f.status}
                            </span>
                        </div>
